export interface PaymentReceiptData {
  customerName: string;
  invoiceNo: number;
  paymentAmount: number;
  paymentMethod: string;
  date: Date;
  remainingBalance: number;
  cashierName: string;
  totalBelanja: number;
  setorGrosir: number;
}

/**
 * Generate payment receipt HTML for wholesale payments
 */
export function generatePaymentReceiptHTML(
  data: PaymentReceiptData,
  format: "A4" | "A6" = "A6",
  showWatermark: boolean = false,
  watermarkText: string = "TOKO EDYSON"
): string {
  const dateObj = typeof data.date === "string" ? new Date(data.date) : data.date;
  const formattedDate = new Intl.DateTimeFormat(["ban", "id"], {
    year: "numeric",
    day: "2-digit",
    month: "short",
    hour: "2-digit",
    minute: "2-digit",
  }).format(dateObj);

  const formattedPaymentAmount = formatIDR(data.paymentAmount);
  const formattedRemainingBalance = formatIDR(data.remainingBalance);
  const formattedTotalBelanja = formatIDR(data.totalBelanja);
  const formattedSetorGrosir = formatIDR(data.setorGrosir);

  const pageSize = format === "A4" ? "A4" : "A6";
  const bodyMaxWidth = format === "A4" ? "210mm" : "105mm";
  const bodyMinHeight = format === "A4" ? "297mm" : "auto";

  return `
<!DOCTYPE html>
<html>
<head>
  <meta charset="UTF-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0">
  <style>
    @media print {
      @page {
        size: ${pageSize};
        margin: 5mm;
      }
      body {
        margin: 0;
        padding: 0;
      }
    }
    .watermark {
      position: absolute;
      top: 50%;
      left: 50%;
      transform: translate(-50%, -50%) rotate(-45deg);
      font-size: 108px;
      font-weight: bold;
      color: rgba(220, 53, 69, 0.25);
      z-index: -1;
      pointer-events: none;
      white-space: nowrap;
      font-family: Arial, sans-serif;
      text-transform: uppercase;
      letter-spacing: 4px;
    }
    body {
      font-family: 'Courier New', monospace;
      font-size: 10px;
      width: 100%;
      max-width: ${bodyMaxWidth};
      min-height: ${bodyMinHeight};
      margin: 0 auto;
      padding: 5mm 4mm;
      color: #000;
      line-height: 1.3;
      background: #fff;
      position: relative;
    }
    .header-container {
      display: flex;
      justify-content: space-between;
      align-items: flex-start;
      margin-bottom: 15px;
      margin-top: 10px;
    }
    .header-left {
      flex: 1;
      padding-left: 5px;
      padding-top: 5px;
    }
    .logo {
      width: 80px;
      height: 74px;
      margin-bottom: 5px;
    }
    .store-name {
      font-weight: bold;
      font-size: 14px;
      margin: 0;
      padding-left: 2px;
    }
    .address {
      font-size: 9px;
      margin: 2px 0;
      padding-left: 2px;
    }
    .header-right {
      text-align: right;
      font-size: 9px;
    }
    .invoice-info {
      margin: 15px 0;
      padding: 8px;
      border: 1px solid #000;
    }
    .invoice-title {
      font-weight: bold;
      font-size: 12px;
      text-align: center;
      margin-bottom: 8px;
    }
    .info-row {
      display: flex;
      justify-content: space-between;
      margin-bottom: 6px;
      font-size: 10px;
    }
    .info-label {
      font-weight: bold;
    }
    .info-value {
      text-align: right;
    }
    .payment-details {
      margin: 15px 0;
      padding: 8px;
      border: 1px solid #000;
    }
    .payment-title {
      font-weight: bold;
      font-size: 12px;
      text-align: center;
      margin-bottom: 8px;
    }
    .amount-row {
      display: flex;
      justify-content: space-between;
      margin-bottom: 8px;
      font-size: 11px;
    }
    .amount-label {
      font-weight: bold;
    }
    .amount-value {
      font-weight: bold;
      color: #0066cc;
    }
    .remaining-row {
      display: flex;
      justify-content: space-between;
      margin-top: 10px;
      padding-top: 10px;
      border-top: 1px solid #000;
      font-size: 11px;
    }
    .remaining-label {
      font-weight: bold;
    }
    .remaining-value {
      font-weight: bold;
      color: #cc0000;
    }
    .footer {
      margin-top: 20px;
      text-align: center;
      font-size: 9px;
    }
    .signature-line {
      height: 35px;
      border-bottom: 1px solid #000;
      margin: 10px auto 5px;
      width: 80%;
    }
    .signature-label {
      text-align: center;
      font-style: italic;
      font-size: 8px;
    }
  </style>
</head>
<body>
  ${showWatermark ? `<div class="watermark">${watermarkText}</div>` : ""}
  <div class="header-container">
    <div class="header-left">
      <img src="${eagleImageUrl()}" class="logo" alt="Logo" />
      <div class="store-name">TOKO EDYSON</div>
      <div class="address">Jl. Raya No. 123</div>
      <div class="address">Telp: 081234567890</div>
    </div>
    <div class="header-right">
      <div>${formattedDate}</div>
    </div>
  </div>

  <div class="invoice-info">
    <div class="invoice-title">BUKTI PEMBAYARAN</div>
    <div class="info-row">
      <span class="info-label">Invoice:</span>
      <span class="info-value">#${data.invoiceNo}</span>
    </div>
    <div class="info-row">
      <span class="info-label">Pelanggan:</span>
      <span class="info-value">${data.customerName}</span>
    </div>
    <div class="info-row">
      <span class="info-label">Kasir:</span>
      <span class="info-value">${data.cashierName}</span>
    </div>
  </div>

  <div class="payment-details">
    <div class="payment-title">DETAIL PEMBAYARAN</div>
    <div class="amount-row">
      <span class="amount-label">Total Belanja:</span>
      <span class="amount-value">${formattedTotalBelanja}</span>
    </div>
    <div class="amount-row">
      <span class="amount-label">Total Setor:</span>
      <span class="amount-value">${formattedSetorGrosir}</span>
    </div>
    <div class="amount-row">
      <span class="amount-label">Pembayaran:</span>
      <span class="amount-value">${formattedPaymentAmount}</span>
    </div>
    <div class="amount-row">
      <span class="amount-label">Metode:</span>
      <span class="amount-value">${data.paymentMethod}</span>
    </div>
    <div class="remaining-row">
      <span class="remaining-label">Sisa Bayaran:</span>
      <span class="remaining-value">${formattedRemainingBalance}</span>
    </div>
  </div>

  ${data.remainingBalance <= 0 ? `
  <div class="pembayaran-lunas" style="margin: 20px 0; padding: 16px; text-align: center; border: 3px solid #000; font-weight: bold; font-size: 18px; letter-spacing: 2px;">
    PEMBAYARAN LUNAS
  </div>
  ` : ""}

  <div class="footer">
    <div class="signature-line"></div>
    <div class="signature-label">Tanda Terima</div>
  </div>
</body>
</html>
  `.trim();
}
